8	export type KeatingCustomProviderType =
9		| "ollama"
10		| "llama.cpp"
11		| "vllm"
12		| "lmstudio"
13		| "gateway"
14		| "openai-completions"
15		| "openai-responses"
16		| "anthropic-messages"
17		| "synthetic";
