26	const AUTO_DISCOVERY_TYPES = new Set<KeatingCustomProviderType>(["ollama", "llama.cpp", "vllm", "lmstudio"]);
27	const OPENAI_COMPATIBLE_TYPES = new Set<KeatingCustomProviderType>([
28		"gateway",
29		"openai-completions",
30		"openai-responses",
31		"synthetic",
