47	function toContextWindow(value: unknown, fallback = 0): number {
48		if (typeof value === "number" && Number.isFinite(value)) return value;
49		if (typeof value === "string") {
50			const parsed = Number.parseInt(value, 10);
51			if (Number.isFinite(parsed)) return parsed;
