154	async function discoverOpenAiCompatibleModels(
155		provider: KeatingCustomProvider,
156	): Promise<{ apiBaseUrl: string; models: Model<Api>[] }> {
157		const candidateBaseUrls = openAiCompatibleBaseUrls(provider);
158	
159		let lastError: unknown;
160		let emptyResult: { apiBaseUrl: string; models: Model<Api>[] } | undefined;
161		for (const apiBaseUrl of candidateBaseUrls) {
162			try {
163				const payload = await fetchJson(`${apiBaseUrl}/models`, provider.apiKey);
164				const records = Array.isArray(payload?.data) ? payload.data : Array.isArray(payload) ? payload : [];
165					const models = records
166						.map((record: any): Model<Api> | null => {
167						const id = String(record?.id ?? record?.name ?? "").trim();
168						if (!id) return null;
169	
170						const contextWindow = toContextWindow(
171							record?.context_window ?? record?.context_length ?? record?.max_context_length ?? record?.max_model_len,
172						);
173						const maxTokens = toContextWindow(record?.max_tokens ?? record?.max_output_tokens, contextWindow || 4096);
174	
175						return {
176							id,
177							name: String(record?.display_name ?? record?.name ?? id),
178							api: manualProviderApi(provider.type),
179							provider: provider.name,
180							baseUrl: apiBaseUrl,
181							reasoning: inferReasoning(record),
182							input: inferInputModes(record),
183							cost: modelCost(),
184							contextWindow,
185							maxTokens,
186						};
187						})
188						.filter((model: Model<Api> | null): model is Model<Api> => model !== null);
189	
190				if (models.length > 0) return { apiBaseUrl, models };
191				emptyResult ??= { apiBaseUrl, models };
192			} catch (error) {
193				lastError = error;
194			}
195		}
196	
197		if (emptyResult) return emptyResult;
198		throw lastError instanceof Error ? lastError : new Error(`Failed to discover models for ${provider.name}`);
199	}
