201	async function discoverOllamaModels(baseUrl: string): Promise<Model<Api>[]> {
202		const trimmedBaseUrl = trimTrailingSlash(baseUrl);
203		const payload = await fetchJson(`${trimmedBaseUrl}/api/tags`);
204		const models = Array.isArray(payload?.models) ? payload.models : [];
205	
206		const discovered = await Promise.all(
207			models.map(async (model: any): Promise<Model<Api> | null> => {
208				const details = await fetchJson(`${trimmedBaseUrl}/api/show`, undefined, {
209					method: "POST",
210					body: { model: model.name },
211				});
212				const capabilities: string[] = (details as any).capabilities || [];
213				if (!capabilities.includes("tools")) return null;
214	
215				const modelInfo: any = details.model_info || {};
216				const architecture = modelInfo["general.architecture"] || "";
217				const contextWindow = toContextWindow(modelInfo[`${architecture}.context_length`], 8192);
218	
219				return {
220					id: model.name,
221					name: model.name,
222					api: "openai-completions" as Api,
223					provider: "",
224					baseUrl: `${trimTrailingSlash(baseUrl)}/v1`,
225					reasoning: capabilities.includes("thinking"),
226					input: ["text"],
227					cost: modelCost(),
228					contextWindow,
229					maxTokens: contextWindow,
230				};
231			}),
232		);
233	
234		return discovered.filter((model): model is Model<Api> => model !== null);
235	}
