237	async function discoverLlamaCppModels(baseUrl: string, apiKey?: string): Promise<Model<Api>[]> {
238		const payload = await fetchJson(`${trimTrailingSlash(baseUrl)}/v1/models`, apiKey);
239		const records = Array.isArray(payload?.data) ? payload.data : [];
240	
241		return records.map((model: any) => {
242			const contextWindow = toContextWindow(model?.context_length, 8192);
243			return {
244				id: String(model.id),
245				name: String(model.id),
246				api: "openai-completions" as Api,
247				provider: "",
248				baseUrl: `${trimTrailingSlash(baseUrl)}/v1`,
249				reasoning: false,
250				input: ["text"],
251				cost: modelCost(),
252				contextWindow,
253				maxTokens: toContextWindow(model?.max_tokens, 4096),
254			};
255		});
256	}
257	
258	async function discoverVllmModels(baseUrl: string, apiKey?: string): Promise<Model<Api>[]> {
259		const payload = await fetchJson(`${trimTrailingSlash(baseUrl)}/v1/models`, apiKey);
260		const records = Array.isArray(payload?.data) ? payload.data : [];
261	
262		return records.map((model: any) => {
263			const contextWindow = toContextWindow(model?.max_model_len, 8192);
264			return {
265				id: String(model.id),
266				name: String(model.id),
267				api: "openai-completions" as Api,
268				provider: "",
269				baseUrl: `${trimTrailingSlash(baseUrl)}/v1`,
270				reasoning: false,
271				input: ["text"],
272				cost: modelCost(),
273				contextWindow,
274				maxTokens: Math.min(contextWindow, 4096),
275			};
276		});
277	}
278	
279	async function discoverLmStudioModels(baseUrl: string): Promise<Model<Api>[]> {
280		const payload = await fetchJson(`${trimTrailingSlash(baseUrl)}/v1/models`);
281		const records = Array.isArray(payload?.data) ? payload.data : [];
282	
283		return records.map((model: any) => {
284			const contextWindow = toContextWindow(model?.context_length ?? model?.max_context_length, 8192);
285			return {
286				id: String(model?.id),
287				name: String(model?.name ?? model?.id),
288				api: "openai-completions" as Api,
289				provider: "",
290				baseUrl: `${trimTrailingSlash(baseUrl)}/v1`,
291				reasoning: inferReasoning(model),
292				input: inferInputModes(model),
293				cost: modelCost(),
294				contextWindow,
295				maxTokens: toContextWindow(model?.max_tokens, contextWindow),
296			};
297		});
298	}
299	
300	export async function discoverCustomProviderModels(provider: KeatingCustomProvider): Promise<Model<Api>[]> {
301		if (AUTO_DISCOVERY_TYPES.has(provider.type)) {
302			let models: Model<Api>[];
303			switch (provider.type) {
304				case "ollama":
305					models = await discoverOllamaModels(provider.baseUrl);
306					break;
307				case "llama.cpp":
308					models = await discoverLlamaCppModels(provider.baseUrl, provider.apiKey);
309					break;
310				case "vllm":
311					models = await discoverVllmModels(provider.baseUrl, provider.apiKey);
312					break;
313				case "lmstudio":
314					models = await discoverLmStudioModels(provider.baseUrl);
315					break;
316				default:
317					models = [];
318			}
319	
320			return models.map((model) => ({ ...model, provider: provider.name }));
321		}
322	
323		if (OPENAI_COMPATIBLE_TYPES.has(provider.type)) {
324			const discovered = await discoverOpenAiCompatibleModels(provider);
325			return discovered.models;
326		}
327	
328		return (provider.models || []).map((model) => ({
329			...model,
330			provider: provider.name,
331			baseUrl: model.baseUrl || provider.baseUrl,
332			api: model.api || manualProviderApi(provider.type),
333		}));
334	}
335	
336	export async function getCustomProviders(): Promise<KeatingCustomProvider[]> {
337		return (await getAppStorage().customProviders.getAll()) as KeatingCustomProvider[];
338	}
339	
340	export async function syncCustomProviderKeys(): Promise<void> {
341		const storage = getAppStorage();
342		const providers = await getCustomProviders();
343	
344		await Promise.all(
345			providers.map(async (provider) => {
346				if (provider.apiKey) {
347					await storage.providerKeys.set(provider.name, provider.apiKey);
348				}
349			}),
350		);
351	}
352	
353	export async function getProviderApiKey(providerName: string): Promise<string | undefined> {
354		const oauthId = providerToOAuthId(providerName);
355		if (oauthId) {
356			const token = await getOAuthAccessToken(oauthId);
357			if (token) return token;
358		}
359	
360		const storage = getAppStorage();
361		const storedKey = await storage.providerKeys.get(providerName);
362		if (storedKey) return storedKey;
363	
364		const customProviders = await getCustomProviders();
365		return customProviders.find((provider) => provider.name === providerName)?.apiKey;
366	}
367	
368	export const UNKNOWN_COST = {
369		input: 0,
370		output: 0,
371		cacheRead: 0,
372		cacheWrite: 0,
373	} as const;
374	
375	export const UNKNOWN_CONTEXT_WINDOW = 8192;
376	export const UNKNOWN_MAX_TOKENS = 4096;
377	
378	function keatingCompatibilityModels(filter?: (provider: string) => boolean): Array<Model<Api>> {
379		const models: Array<Model<Api>> = [];
380		const maybeAdd = (provider: string, baseUrl: string) => {
381			if (filter && !filter(provider)) return;
382			models.push({
383				id: "MiniMax-M3",
384				name: "MiniMax-M3",
385				api: "openai-completions" as Api,
386				provider,
387				baseUrl,
388				reasoning: true,
389				input: ["text"],
390				cost: UNKNOWN_COST,
391				contextWindow: 1_000_000,
392				maxTokens: 4096,
393			});
394		};
395		maybeAdd("minimax", "https://api.minimax.io/v1");
396		maybeAdd("minimax-cn", "https://api.minimaxi.com/v1");
397		return models;
398	}
399	
400	export async function getSelectableModels(
401		filter?: (provider: string) => boolean,
402	): Promise<Array<Model<Api>>> {
403		const models: Array<Model<Api>> = [];
404	
405		if (!filter || filter(DIO_PROVIDER_ID)) {
406			models.push(DIO_DEFAULT_MODEL);
407		}
408	
409		for (const provider of getProviders()) {
410			if (!filter || filter(provider)) {
411				models.push(...(getModels(provider as any) as Array<Model<Api>>));
412			}
413		}
414	
415		models.push(...keatingCompatibilityModels(filter));
416	
417		const customProviders = await getCustomProviders();
418		const customModels = await Promise.all(
419			customProviders.map(async (provider) => {
420				try {
421					return await discoverCustomProviderModels(provider);
422				} catch (error) {
423					console.warn(`Skipping unavailable provider ${provider.name}:`, error);
424					return [];
425				}
426			}),
427		);
428	
429		models.push(...customModels.flat());
430		return models;
431	}
432	
433	export function buildSavedModel(saved: any): Model<Api> {
434		return {
435			id: saved.id,
436			name: saved.name,
437			api: saved.api as Api,
438			provider: saved.provider,
439			baseUrl: saved.baseUrl || "",
440			reasoning: saved.reasoning,
441			input: saved.vision ? (["text", "image"] as Array<"text" | "image">) : (["text"] as Array<"text" | "image">),
442			cost: UNKNOWN_COST,
443			contextWindow: UNKNOWN_CONTEXT_WINDOW,
444			maxTokens: UNKNOWN_MAX_TOKENS,
445		};
446	}
