function keatingCompatibilityModels(filter?: (provider: string) => boolean): Array<Model<Api>> {
	const models: Array<Model<Api>> = [];
	const maybeAdd = (provider: string, baseUrl: string) => {
		if (filter && !filter(provider)) return;
		models.push({
			id: "MiniMax-M3",
			name: "MiniMax-M3",
			api: "openai-completions" as Api,
			provider,
			baseUrl,
			reasoning: true,
			input: ["text"],
			cost: UNKNOWN_COST,
			contextWindow: 1_000_000,
			maxTokens: 4096,
		});
	};
	maybeAdd("minimax", "https://api.minimax.io/v1");
	maybeAdd("minimax-cn", "https://api.minimaxi.com/v1");
	return models;
}

export async function getSelectableModels(
	filter?: (provider: string) => boolean,
): Promise<Array<Model<Api>>> {
	const models: Array<Model<Api>> = [];

	if (!filter || filter(DIO_PROVIDER_ID)) {
		models.push(DIO_DEFAULT_MODEL);
	}

	for (const provider of getProviders()) {
		if (!filter || filter(provider)) {
			models.push(...(getModels(provider as any) as Array<Model<Api>>));
		}
	}

	models.push(...keatingCompatibilityModels(filter));

	const customProviders = await getCustomProviders();
	const customModels = await Promise.all(
		customProviders.map(async (provider) => {
			try {
				return await discoverCustomProviderModels(provider);
			} catch (error) {
				console.warn(`Skipping unavailable provider ${provider.name}:`, error);
				return [];
			}
		}),
	);

	models.push(...customModels.flat());
	return models;
}

export function buildSavedModel(saved: any): Model<Api> {
	return {
		id: saved.id,
		name: saved.name,
		api: saved.api as Api,
		provider: saved.provider,
		baseUrl: saved.baseUrl || "",
		reasoning: saved.reasoning,
		input: saved.vision ? (["text", "image"] as Array<"text" | "image">) : (["text"] as Array<"text" | "image">),
		cost: UNKNOWN_COST,
		contextWindow: UNKNOWN_CONTEXT_WINDOW,
		maxTokens: UNKNOWN_MAX_TOKENS,
	};
}

