646	async function generateOpenAiImage(params: {
647		prompt: string;
648		model: string;
649		size: string;
650		quality: string;
651	}): Promise<{ dataUrl: string; mimeType: string }> {
652		const apiKey = await getProviderApiKey("openai");
653		if (!apiKey) {
654			throw new Error("No OpenAI API key configured. Add one in Settings -> Providers & Models -> OpenAI.");
655		}
656	
657		const proxied = proxiedProviderRequestUrl("https://api.openai.com/v1/images/generations");
658		const response = await fetch(proxied.url, {
659			method: "POST",
660			headers: {
661				accept: "application/json",
662				"content-type": "application/json",
663				Authorization: `Bearer ${apiKey}`,
664				"x-target-url": proxied.targetBaseUrl,
665			},
666			body: JSON.stringify({
667				model: params.model,
668				prompt: params.prompt,
669				size: params.size,
670				quality: params.quality,
671				n: 1,
672			}),
673		});
674	
675		const payload = await response.json().catch(async () => ({ error: { message: await response.text().catch(() => response.statusText) } }));
676		if (!response.ok) {
677			const message = payload?.error?.message ?? response.statusText;
678			throw new Error(`OpenAI image generation failed (${response.status}): ${String(message).slice(0, 500)}`);
679		}
680	
681		const b64 = payload?.data?.[0]?.b64_json;
682		if (!b64 || typeof b64 !== "string") {
683			throw new Error("OpenAI image generation returned no base64 image data.");
684		}
685	
686		return { dataUrl: `data:image/png;base64,${b64}`, mimeType: "image/png" };
687	}
