1	import type { AgentTool } from "@earendil-works/pi-agent-core";
2	
3	export const KEATING_VOICE_TOOL_NAME = "keating_voice";
4	export const GEMINI_LIVE_SPEECH_MODEL = "gemini-3.1-flash-live-preview";
5	export const DEFAULT_SPEECH_VOICE = "Kore";
6	const SPEECH_SETTINGS_KEY = "keating:web:speech";
7	export const RECEIVE_SAMPLE_RATE = 24_000;
8	
9	const VOICE_TAGS = new Set([
10		"explain",
11		"question",
12		"verify",
13		"redirect",
14		"encourage",
15		"pause",
16		"recap",
17	]);
18	
19	export type SpeechProviderId =
20		| "gemini-live"
21		| "openai-tts"
22		| "openai-realtime"
23		| "supertonic-3"
24		| string; // allows "custom:<id>"
25	
26	export interface CustomSpeechModel {
27		id: string;            // stable client id; storage key is `custom:${id}`
28		label: string;         // shown in dropdown
29		baseUrl: string;       // for OpenAI-compatible TTS endpoints
30		model: string;         // model id passed in request body
31		voice: string;         // default voice
32		providerKey: string;   // which providerKeys entry to use ("openai", custom name)
33		apiPath?: string;      // default "/v1/audio/speech"
34	}
35	
36	export interface WebSpeechSettings {
37		enabled: boolean;
38		/** Active provider. Defaults to "gemini-live" for back-compat. */
39		providerId: SpeechProviderId;
40		/** Active model for the chosen provider. */
41		model: string;
42		/** Active voice for the chosen provider. */
43		voiceName: string;
44		/** User-defined OpenAI-compatible TTS endpoints. */
45		customModels: CustomSpeechModel[];
46		/** When true, Realtime providers may capture mic input. */
47		microphoneEnabled: boolean;
48	}
49	
50	export interface VoiceUtterance {
51		text: string;
52		voice: string;
53		tags: string[];
54		pace: string;
55		affect: string;
56	}
57	
58	export const DEFAULT_WEB_SPEECH_SETTINGS: WebSpeechSettings = {
59		enabled: false,
60		providerId: "gemini-live",
61		model: GEMINI_LIVE_SPEECH_MODEL,
62		voiceName: DEFAULT_SPEECH_VOICE,
63		customModels: [],
64		microphoneEnabled: false,
65	};
66	
67	function cleanString(value: unknown): string {
68		return typeof value === "string" ? value.trim() : "";
69	}
70	
71	function cleanTags(value: unknown): string[] {
72		const rawTags = Array.isArray(value) ? value : typeof value === "string" ? value.split(",") : [];
73		const tags = rawTags
74			.map((tag) => cleanString(tag).toLowerCase())
75			.filter((tag) => VOICE_TAGS.has(tag));
76		return Array.from(new Set(tags));
77	}
78	
79	export function normalizeVoiceUtterance(input: Record<string, unknown>, settings: WebSpeechSettings): VoiceUtterance {
80		const text = cleanString(input.text);
81		if (!text) throw new Error("keating_voice requires non-empty text.");
82	
83		return {
84			text,
85			voice: cleanString(input.voice) || settings.voiceName,
86			tags: cleanTags(input.tags ?? input.tag),
87			pace: cleanString(input.pace) || "conversational",
88			affect: cleanString(input.affect) || "warm",
89		};
90	}
91	
92	export function voiceTagLine(utterance: VoiceUtterance): string {
93		const tags = utterance.tags.length ? utterance.tags.join(",") : "none";
94		return `[voice voice=${utterance.voice} tags=${tags} pace=${utterance.pace} affect=${utterance.affect}] ${utterance.text}`;
95	}
96	
97	export function loadWebSpeechSettings(): WebSpeechSettings {
98		if (typeof window === "undefined") return DEFAULT_WEB_SPEECH_SETTINGS;
99		try {
100			const raw = window.localStorage.getItem(SPEECH_SETTINGS_KEY);
101			if (!raw) return DEFAULT_WEB_SPEECH_SETTINGS;
102			const parsed = JSON.parse(raw) as Partial<WebSpeechSettings>;
103			const customModels = Array.isArray(parsed.customModels)
104				? parsed.customModels.filter(
105						(m): m is CustomSpeechModel =>
106							!!m && typeof m.id === "string" && typeof m.baseUrl === "string" && typeof m.model === "string",
107					)
108				: [];
109			return {
110				enabled: parsed.enabled === true,
111				providerId: cleanString(parsed.providerId) || DEFAULT_WEB_SPEECH_SETTINGS.providerId,
112				model: cleanString(parsed.model) || DEFAULT_WEB_SPEECH_SETTINGS.model,
113				voiceName: cleanString(parsed.voiceName) || DEFAULT_WEB_SPEECH_SETTINGS.voiceName,
114				customModels,
115				microphoneEnabled: parsed.microphoneEnabled === true,
116			};
117		} catch {
118			return DEFAULT_WEB_SPEECH_SETTINGS;
119		}
120	}
121	
122	export function saveWebSpeechSettings(settings: WebSpeechSettings): void {
123		if (typeof window === "undefined") return;
124		window.localStorage.setItem(SPEECH_SETTINGS_KEY, JSON.stringify(settings));
125	}
126	
127	let audioContext: AudioContext | null = null;
128	let scheduledUntil = 0;
129	
130	export function getAudioContext(): AudioContext | null {
131		if (typeof window === "undefined") return null;
132		const AudioContextCtor = window.AudioContext || window.webkitAudioContext;
133		if (!AudioContextCtor) return null;
134		audioContext ??= new AudioContextCtor();
135		return audioContext;
136	}
137	
138	export async function primeSpeechAudio(): Promise<void> {
139		const context = getAudioContext();
140		if (context && context.state === "suspended") await context.resume();
141	}
142	
143	function decodeBase64Pcm(base64: string): Int16Array {
144		const binary = window.atob(base64);
145		const bytes = new Uint8Array(binary.length);
146		for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
147		return new Int16Array(bytes.buffer);
148	}
149	
150	export function schedulePcmAudio(base64: string, sampleRate = RECEIVE_SAMPLE_RATE): boolean {
151		const context = getAudioContext();
152		if (!context) return false;
153	
154		const pcm = decodeBase64Pcm(base64);
155		if (pcm.length === 0) return false;
156	
157		const buffer = context.createBuffer(1, pcm.length, sampleRate);
158		const channel = buffer.getChannelData(0);
159		for (let i = 0; i < pcm.length; i += 1) channel[i] = pcm[i] / 32768;
160	
161		const source = context.createBufferSource();
162		source.buffer = buffer;
