1	import {
2		getAudioContext,
3		type SpeechProvider,
4		type SpeechSynthesisRequest,
5		type SpeechSynthesisResult,
6	} from "../speech";
7	import { withApiRetry } from "../api-retry";
8	
9	const REALTIME_MODELS = [
10		{ value: "gpt-realtime", label: "gpt-realtime (latest)" },
11		{ value: "gpt-realtime-mini", label: "gpt-realtime-mini" },
12		{ value: "gpt-4o-realtime-preview-2024-12-17", label: "gpt-4o-realtime-preview" },
13		{ value: "gpt-4o-mini-realtime-preview-2024-12-17", label: "gpt-4o-mini-realtime-preview" },
14	];
15	
16	const REALTIME_VOICES = [
17		"alloy",
18		"ash",
19		"ballad",
20		"cedar",
21		"coral",
22		"echo",
23		"marin",
24		"sage",
25		"shimmer",
26		"verse",
27	];
28	
29	async function mintEphemeralKey(apiKey: string, model: string, voice: string, signal?: AbortSignal): Promise<string> {
30		const response = await withApiRetry(async () => {
31			const result = await fetch("https://api.openai.com/v1/realtime/sessions", {
32				method: "POST",
33				headers: {
34					"Content-Type": "application/json",
35					Authorization: `Bearer ${apiKey}`,
36				},
37				body: JSON.stringify({
38					model,
39					voice,
40					modalities: ["audio", "text"],
41				}),
42				signal,
43			});
44			if (!result.ok) {
45				const errText = await result.text().catch(() => "");
46				const retryAfter = result.headers.get("retry-after");
47				throw new Error(`Realtime session mint failed (${result.status}): ${errText.slice(0, 200) || result.statusText}${retryAfter ? ` retry-after: ${retryAfter}` : ""}`);
48			}
49			return result;
50		}, { signal });
51		const data = (await response.json()) as { client_secret?: { value?: string } };
52		const value = data.client_secret?.value;
53		if (!value) throw new Error("Realtime session mint returned no client_secret.value");
54		return value;
55	}
56	
57	async function attachMicrophone(pc: RTCPeerConnection): Promise<MediaStream | null> {
58		if (typeof navigator === "undefined" || !navigator.mediaDevices?.getUserMedia) return null;
59		try {
60			const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
61			stream.getAudioTracks().forEach((track) => pc.addTrack(track, stream));
62			return stream;
63		} catch (err) {
64			console.warn("[keating:realtime] microphone unavailable", err);
65			return null;
66		}
67	}
68	
69	async function synthesize(request: SpeechSynthesisRequest): Promise<SpeechSynthesisResult> {
70		const { utterance, settings, getApiKey, signal } = request;
71		const apiKey = await getApiKey("openai");
72		if (!apiKey) {
73			throw new Error("No OpenAI API key configured. Add one in Settings → Providers & Models.");
74		}
75	
76		const model = settings.model || "gpt-realtime";
77		const voice = utterance.voice || "marin";
78	
79		const ephemeralKey = await mintEphemeralKey(apiKey, model, voice, signal);
80	
81		const pc = new RTCPeerConnection();
82		const audioEl = typeof document !== "undefined" ? document.createElement("audio") : null;
83		if (audioEl) {
84			audioEl.autoplay = true;
85			audioEl.style.display = "none";
86			document.body.appendChild(audioEl);
87		}
88	
89		let audioChunks = 0;
90		let playedChunks = 0;
91		let micStream: MediaStream | null = null;
92		let cleanedUp = false;
93	
94		const cleanup = () => {
95			if (cleanedUp) return;
96			cleanedUp = true;
97			try { pc.close(); } catch {}
98			micStream?.getTracks().forEach((t) => t.stop());
99			if (audioEl) {
100				try { audioEl.pause(); } catch {}
101				audioEl.srcObject = null;
102				audioEl.remove();
103			}
104		};
105	
106		if (signal?.aborted) {
107			cleanup();
108			throw new Error("OpenAI Realtime aborted before start.");
109		}
110		signal?.addEventListener("abort", cleanup, { once: true });
111	
112		pc.ontrack = (event) => {
113			audioChunks += 1;
114			if (audioEl && event.streams[0]) {
115				audioEl.srcObject = event.streams[0];
116				audioEl.play().then(() => { playedChunks += 1; }).catch(() => {});
117			}
118		};
119	
120		const dataChannel = pc.createDataChannel("oai-events");
121	
122		if (settings.microphoneEnabled) {
123			micStream = await attachMicrophone(pc);
124		}
125	
126		return await new Promise<SpeechSynthesisResult>(async (resolve, reject) => {
127			const timer = setTimeout(() => {
128				cleanup();
129				reject(new Error("OpenAI Realtime response timed out."));
130			}, 60_000);
131	
132			dataChannel.addEventListener("open", () => {
133				dataChannel.send(JSON.stringify({
134					type: "response.create",
135					response: {
136						modalities: ["audio", "text"],
137						instructions: `Speak this learner-facing line exactly. Affect: ${utterance.affect}. Pace: ${utterance.pace}.\n\n${utterance.text}`,
138					},
139				}));
140			});
141	
142			dataChannel.addEventListener("message", (event) => {
143				try {
144					const msg = JSON.parse(event.data);
145					if (msg.type === "response.done") {
146						clearTimeout(timer);
147						cleanup();
148						resolve({
149							audioChunks,
150							playedChunks,
151							transcript: utterance.text,
152							warning: settings.microphoneEnabled && !micStream ? "Microphone unavailable" : undefined,
153						});
154					}
155					if (msg.type === "error") {
156						clearTimeout(timer);
157						cleanup();
158						reject(new Error(`Realtime error: ${msg.error?.message ?? "unknown"}`));
159					}
160				} catch {}
161			});
162	
163			try {
164				getAudioContext();
165				const offer = await pc.createOffer();
166				await pc.setLocalDescription(offer);
167	
168				const sdpResponse = await withApiRetry(async () => {
169					const result = await fetch(`https://api.openai.com/v1/realtime?model=${encodeURIComponent(model)}`, {
170						method: "POST",
171						headers: {
172							Authorization: `Bearer ${ephemeralKey}`,
173							"Content-Type": "application/sdp",
174						},
175						body: offer.sdp,
176						signal,
177					});
