          return [{
            type: "tool-call" as const,
            toolCallId: part.id ?? `tool-${index}`,
            toolName: part.name ?? "tool",
            args: part.arguments ?? {},
            argsText: JSON.stringify(part.arguments ?? {}),
            result: part.__toolResult ?? part.__toolDetails,
            isError: part.__toolError,
