	return {
		text,
		voice: cleanString(input.voice) || settings.voiceName,
		tags: cleanTags(input.tags ?? input.tag),
		pace: cleanString(input.pace) || "conversational",
		affect: cleanString(input.affect) || "warm",
	};
}

