// Renders a per-share OpenGraph card to PNG using resvg-wasm. The SVG is
// hand-authored (no satori/yoga dependency) and rasterized with the bundled
// Inter font. Both the wasm binary and the font ship as server assets
// (web/server/assets/**). Callers must handle a thrown error by falling back to
// the static /og-image.png so a render failure never breaks an embed.
import { useStorage } from "nitro/storage";

let wasmReady: Promise<void> | null = null;
let fontBuffer: Uint8Array | null = null;

async function readAsset(key: string): Promise<Uint8Array> {
	const raw = (await useStorage("assets:server").getItemRaw(key)) as
		| ArrayBuffer
		| Uint8Array
		| Buffer
		| null;
	if (!raw) throw new Error(`Missing server asset: ${key}`);
	if (raw instanceof Uint8Array) return raw;
	return new Uint8Array(raw as ArrayBuffer);
}

async function ensureWasm(): Promise<void> {
	if (!wasmReady) {
		wasmReady = (async () => {
			const { initWasm } = await import("@resvg/resvg-wasm");
			const bytes = await readAsset("resvg.wasm");
			await initWasm(bytes);
		})();
	}
	return wasmReady;
}

async function getFont(): Promise<Uint8Array> {
	if (!fontBuffer) fontBuffer = await readAsset("fonts/Inter-SemiBold.ttf");
	return fontBuffer;
}

function escapeXml(value: string): string {
	return value
		.replace(/&/g, "&amp;")
		.replace(/</g, "&lt;")
		.replace(/>/g, "&gt;")
		.replace(/"/g, "&quot;")
		.replace(/'/g, "&apos;");
}

/** Greedy word-wrap into at most `maxLines` lines of ~`maxChars` characters. */
function wrapLines(text: string, maxChars: number, maxLines: number): string[] {
	const words = text.split(/\s+/).filter(Boolean);
	const lines: string[] = [];
	let current = "";
	for (const word of words) {
		const candidate = current ? `${current} ${word}` : word;
		if (candidate.length > maxChars && current) {
			lines.push(current);
			current = word;
			if (lines.length === maxLines - 1) break;
		} else {
			current = candidate;
		}
	}
	if (current && lines.length < maxLines) lines.push(current);
	if (lines.length === maxLines && words.join(" ").length > lines.join(" ").length) {
		lines[maxLines - 1] = `${lines[maxLines - 1].replace(/\s*\S*$/, "")}…`;
	}
	return lines;
}

function buildSvg(title: string, subtitle: string): string {
	const titleLines = wrapLines(title || "Shared Keating session", 24, 3);
	const subtitleLines = wrapLines(subtitle || "A Socratic tutoring session", 56, 2);
	const titleStartY = 250 - (titleLines.length - 1) * 38;

	const titleTspans = titleLines
		.map(
			(line, i) =>
				`<text x="80" y="${titleStartY + i * 76}" font-family="Inter" font-size="64" font-weight="700" fill="#f1ece0">${escapeXml(line)}</text>`,
		)
		.join("");
	const subtitleTspans = subtitleLines
		.map(
			(line, i) =>
				`<text x="80" y="${470 + i * 38}" font-family="Inter" font-size="28" fill="#9aa0a6">${escapeXml(line)}</text>`,
		)
		.join("");

	return `<svg width="1200" height="630" viewBox="0 0 1200 630" xmlns="http://www.w3.org/2000/svg">
  <rect width="1200" height="630" fill="#0c0e10"/>
  <rect x="0" y="0" width="1200" height="8" fill="#d4a373"/>
  <text x="80" y="120" font-family="Inter" font-size="30" font-weight="700" fill="#d4a373">Keating</text>
  <text x="80" y="158" font-family="Inter" font-size="22" fill="#6b7178">The Hyperteacher · Shared session</text>
  ${titleTspans}
  ${subtitleTspans}
  <text x="80" y="588" font-family="Inter" font-size="22" fill="#6b7178">keating.help</text>
</svg>`;
}

/** Render the per-share OG card to a PNG. Throws on any failure. */
export async function renderShareOgPng(title: string, subtitle: string): Promise<Uint8Array> {
	await ensureWasm();
	const font = await getFont();
	const { Resvg } = await import("@resvg/resvg-wasm");
	const svg = buildSvg(title, subtitle);
	const resvg = new Resvg(svg, {
		fitTo: { mode: "width", value: 1200 },
		font: { fontBuffers: [font], defaultFontFamily: "Inter", loadSystemFonts: false },
	});
	return resvg.render().asPng();
}

